func enrollDatabaseURL() string {
	if dsn := os.Getenv("DATABASE_URL"); dsn != "" {
		return dsn
	}
	return "postgresql://postgres:password@localhost:5432/postgres"
}

func setupEnrollTestData(ctx context.Context, pool *pgxpool.Pool) error {
	cleanupEnrollTestData(ctx, pool)

	sqls := []struct {
		query string
		args  []any
	}{
		{
			`INSERT INTO categories (category_id, name, path) VALUES ($1, 'テストカテゴリ', 'enroll-test')`,
			[]any{enrollTestCategoryID},
		},
		{
			`INSERT INTO authors (author_id, name, profile) VALUES ($1, 'テスト著者', 'テストプロフィール')`,
			[]any{enrollTestAuthorID},
		},
		{
			`INSERT INTO users (user_id, nickname) VALUES ($1, 'テストユーザー')`,
			[]any{enrollTestUserID},
		},
		{
			`INSERT INTO courses (course_id, title, description, slug, tags, publish_status, category_id, author_id, visibility)
			 VALUES ($1, 'テストコース', 'テスト説明', 'enroll-test-course', '[]', 'published', $2, $3, 'public')`,
			[]any{enrollTestCourseID, enrollTestCategoryID, enrollTestAuthorID},
		},
		{
			`INSERT INTO course_sections (course_section_id, course_id, index, title, description)
			 VALUES ($1, $2, 0, 'テストセクション', 'セクション説明')`,
			[]any{enrollTestSectionID, enrollTestCourseID},
		},
		{
			`INSERT INTO course_section_topics (course_section_topic_id, course_id, course_section_id, index, title, description, prerequisites, knowledge, flow, quiz, completion_criteria)
			 VALUES ($1, $2, $3, 0, 'テストトピック', 'トピック説明', '', '', '', '', '')`,
			[]any{enrollTestTopicID, enrollTestCourseID, enrollTestSectionID},
		},
	}

	for _, s := range sqls {
		if _, err := pool.Exec(ctx, s.query, s.args...); err != nil {
			return fmt.Errorf("テストデータの挿入に失敗しました: %w", err)
		}
	}
	return nil
}

func cleanupEnrollTestData(ctx context.Context, pool *pgxpool.Pool) {
	_, _ = pool.Exec(ctx, `DELETE FROM user_topic_progresses WHERE user_id = $1`, enrollTestUserID)
	_, _ = pool.Exec(ctx, `DELETE FROM course_section_topics WHERE course_id = $1`, enrollTestCourseID)
	_, _ = pool.Exec(ctx, `DELETE FROM course_sections WHERE course_id = $1`, enrollTestCourseID)
	_, _ = pool.Exec(ctx, `DELETE FROM courses WHERE course_id = $1`, enrollTestCourseID)
	_, _ = pool.Exec(ctx, `DELETE FROM users WHERE user_id = $1`, enrollTestUserID)
	_, _ = pool.Exec(ctx, `DELETE FROM authors WHERE author_id = $1`, enrollTestAuthorID)
	_, _ = pool.Exec(ctx, `DELETE FROM categories WHERE category_id = $1`, enrollTestCategoryID)
}

func TestPostEnrollmentHandlerMedium(t *testing.T) {
	ctx := context.Background()
	pool, err := pgxpool.New(ctx, enrollDatabaseURL())
	if err != nil {
		t.Fatalf("DBへの接続に失敗しました: %v", err)
	}
	defer pool.Close()

	if err := setupEnrollTestData(ctx, pool); err != nil {
		t.Fatalf("テストデータのセットアップに失敗しました: %v", err)
	}
	t.Cleanup(func() { cleanupEnrollTestData(ctx, pool) })

	q := db.New(pool)
	handler := NewHandler(NewEnrollCourseUsecase(NewSqrcCourseRepository(q), NewSqrcUserTopicProgressRepository(q)))

	newEnrollRequest := func(t *testing.T, body string) *http.Request {
		t.Helper()
		req := httptest.NewRequest("POST", "/v1/courses/"+enrollTestCourseID+"/enrollment", strings.NewReader(body))
		req.SetPathValue("courseId", enrollTestCourseID)
		return req
	}

	t.Run("受講を開始するとtopicIdが返る", func(t *testing.T) {
		t.Cleanup(func() {
			_, _ = pool.Exec(ctx, `DELETE FROM user_topic_progresses WHERE user_id = $1`, enrollTestUserID)
		})

		req := newEnrollRequest(t, `{"userId":"`+enrollTestUserID+`"}`)
		w := httptest.NewRecorder()

		handler.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusCreated {
			t.Fatalf("ステータスコードが201であること: got %d", w.Result().StatusCode)
		}
		var body map[string]string
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body["topicId"] != enrollTestTopicID {
			t.Errorf("topicIdが一致すること: got %q", body["topicId"])
		}
	})

	t.Run("sectionNumberを指定して受講を開始できる", func(t *testing.T) {
		t.Cleanup(func() {
			_, _ = pool.Exec(ctx, `DELETE FROM user_topic_progresses WHERE user_id = $1`, enrollTestUserID)
		})

		req := newEnrollRequest(t, `{"userId":"`+enrollTestUserID+`","sectionNumber":0}`)
		w := httptest.NewRecorder()

		handler.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusCreated {
			t.Fatalf("ステータスコードが201であること: got %d", w.Result().StatusCode)
		}
		var body map[string]string
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body["topicId"] != enrollTestTopicID {
			t.Errorf("topicIdが一致すること: got %q", body["topicId"])
		}
	})

	t.Run("sectionNumberとtopicNumberを指定して受講を開始できる", func(t *testing.T) {
		t.Cleanup(func() {
			_, _ = pool.Exec(ctx, `DELETE FROM user_topic_progresses WHERE user_id = $1`, enrollTestUserID)
		})

		req := newEnrollRequest(t, `{"userId":"`+enrollTestUserID+`","sectionNumber":0,"topicNumber":0}`)
		w := httptest.NewRecorder()

		handler.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusCreated {
			t.Fatalf("ステータスコードが201であること: got %d", w.Result().StatusCode)
		}
		var body map[string]string
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body["topicId"] != enrollTestTopicID {
			t.Errorf("topicIdが一致すること: got %q", body["topicId"])
		}
	})

	t.Run("topicNumberのみ指定した場合400を返す", func(t *testing.T) {
		req := newEnrollRequest(t, `{"userId":"`+enrollTestUserID+`","topicNumber":0}`)
		w := httptest.NewRecorder()

		handler.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusBadRequest {
			t.Errorf("ステータスコードが400であること: got %d", w.Result().StatusCode)
		}
		var body map[string]string
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body["code"] != "INPUT_VALIDATION_ERROR" {
			t.Errorf("codeが一致すること: got %q", body["code"])
		}
	})

	t.Run("存在しないsectionNumberを指定した場合400を返す", func(t *testing.T) {
		req := newEnrollRequest(t, `{"userId":"`+enrollTestUserID+`","sectionNumber":999}`)
		w := httptest.NewRecorder()

		handler.PostEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusBadRequest {
			t.Errorf("ステータスコードが400であること: got %d", w.Result().StatusCode)
		}
		var body map[string]string
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
		}
		if body["code"] != "INPUT_VALIDATION_ERROR" {
			t.Errorf("codeが一致すること: got %q", body["code"])
		}
	})
}

package commands

import (
	"errors"
	"time"
)

type Topic struct {
	topicId            string
	title              string
	description        string
	prerequisites      string
	knowledge          string
	flow               string
	quiz               string
	completionCriteria string
	number             int
}

type Section struct {
	sectionId   string
	title       string
	description string
	number      int
	topics      []Topic
}

type Author struct {
	authorId string
	name     string
}

type Category struct {
	categoryId string
	name       string
}

type Course struct {
	courseId      string
	title         string
	description   string
	slug          string
	tags          []string
	publishStatus string
	category      Category
	publishedAt   *string
	author        Author
	visibility    string
	sections      []Section
}

type EnrollNumber struct {
	SectionNumber *int
	TopicNumber   *int
}

type ProgressRecord struct {
	userTopicProgressId  string
	courseSectionId      string
	courseSectionTopicId string
	sectionNumber        int
	topicNumber          int
	status               string
	startedAt            string
	completedAt          *string
}

type Progress struct {
	courseId string
	userId   string
	records  []ProgressRecord
}

func (p *Progress) lastTopic() (status string, sectionNumber int, topicNumber int) {
	var maxRecord ProgressRecord = ProgressRecord{sectionNumber: 0, topicNumber: 0, status: "NOT_STARTED"}

	for _, record := range p.records {
		if record.sectionNumber > maxRecord.sectionNumber || (record.sectionNumber == maxRecord.sectionNumber && record.topicNumber > maxRecord.topicNumber) {
			maxRecord = record
		}
	}

	return maxRecord.status, maxRecord.sectionNumber, maxRecord.topicNumber
}

func (p *Progress) start(section Section, topic Topic) string {
	for _, record := range p.records {
		if record.courseSectionTopicId == topic.topicId && record.courseSectionId == section.sectionId {
			return topic.topicId
		}
	}

	p.records = append(p.records, ProgressRecord{
		courseSectionId:      section.sectionId,
		courseSectionTopicId: topic.topicId,
		sectionNumber:        section.number,
		topicNumber:          topic.number,
		status:               "IN_PROGRESS",
		startedAt:            time.Now().Format(time.RFC3339),
		completedAt:          nil,
	})
	return topic.topicId
}

var ErrEnrollmentNumberIsNotFound = errors.New("enrollment number is not found")

func (course *Course) enroll(enrollNumber EnrollNumber, progress *Progress) (string, error) {
	if enrollNumber.SectionNumber == nil && enrollNumber.TopicNumber != nil {
		return "", ErrTopicNumberRequireSectionNumber
	}

	sectionNumber := 0
	topicNumber := 0

	if enrollNumber.SectionNumber != nil {
		sectionNumber = *enrollNumber.SectionNumber

		if enrollNumber.TopicNumber == nil {
			topicNumber = 0
		} else {
			topicNumber = *enrollNumber.TopicNumber
		}
	} else {
		status, lastSectionNumber, lastTopicNumber := progress.lastTopic()
		if status == "COMPLETED" {
			nextPosition, err := course.nextTopic(TopicPosition{sectionNumber: lastSectionNumber, topicNumber: lastTopicNumber})
			if err != nil {
				return "", ErrEnrollmentNumberIsNotFound
			}
			sectionNumber, topicNumber = nextPosition.sectionNumber, nextPosition.topicNumber
		} else if status == "IN_PROGRESS" {
			sectionNumber = lastSectionNumber
			topicNumber = lastTopicNumber
		} else {
			sectionNumber = 0
			topicNumber = 0
		}
	}

	section, topic, err := course.getTopic(sectionNumber, topicNumber)
	if err != nil {
		return "", ErrEnrollmentNumberIsNotFound
	}

	topicId := progress.start(section, topic)

	return topicId, nil
}

type TopicPosition struct {
	sectionNumber int
	topicNumber   int
}


var ErrTopicPositionOutOfRange = errors.New("topic position is out of range")

func (course *Course) getTopic(sectionNumber int, topicNumber int) (Section, Topic, error) {
	if sectionNumber < 0 || sectionNumber >= len(course.sections) {
		return Section{}, Topic{}, ErrTopicPositionOutOfRange
	}
	section := course.sections[sectionNumber]
	if topicNumber < 0 || topicNumber >= len(section.topics) {
		return Section{}, Topic{}, ErrTopicPositionOutOfRange
	}
	return section, section.topics[topicNumber], nil
}

func (course *Course) nextTopic(currentTopicPosition TopicPosition) (topicPosition TopicPosition, err error) {
	if currentTopicPosition.sectionNumber < 0 || currentTopicPosition.sectionNumber >= len(course.sections) {
		return TopicPosition{}, ErrTopicPositionOutOfRange
	}

	section := course.sections[currentTopicPosition.sectionNumber]
	if currentTopicPosition.topicNumber < 0 || currentTopicPosition.topicNumber >= len(section.topics) {
		return TopicPosition{}, ErrTopicPositionOutOfRange
	}

	if currentTopicPosition.topicNumber == len(section.topics)-1 {
		if currentTopicPosition.sectionNumber == len(course.sections)-1 {
			return TopicPosition{}, ErrTopicPositionOutOfRange
		}
		return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber + 1, topicNumber: 0}, nil
	}

	return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber, topicNumber: currentTopicPosition.topicNumber + 1}, nil
}
